const { execSync } = require('child_process');

try {
  const raw = execSync(
    'python3 /Users/mantou/hk-trading-bot/n8n_heat_acceleration_detector.py 2>/dev/null',
    { timeout: 60000, encoding: 'utf-8' }
  );

  const data = JSON.parse(raw);
  return [{ json: data }];

} catch(e) {
  return [{ json: { error: e.message } }];
}

const data = $input.all()[0].json;

// 筛选K值 > 0.3 的财经关键词
const accelerating = data.all_keywords_with_k.filter(kw => 
  kw.k_value > 0.3
);

if (accelerating.length === 0) {
  // 没有加速关键词，停止流程
  return [];
}

// 按K值排序
accelerating.sort((a, b) => b.k_value - a.k_value);

return [{ json: { accelerating, stats: data.statistics } }];

